import { Injectable, inject } from '@angular/core';
import { SupabaseService } from '../Base/supabase.service';
import { BehaviorSubject } from 'rxjs';

export interface Unit {
  id: string;
  name: string;
  symbol: string;
  type: 'weight' | 'volume' | 'piece' | 'package';
}

@Injectable({
  providedIn: 'root'
})
export class UnitService {
  private supabaseService = inject(SupabaseService);

  private unitsSubject = new BehaviorSubject<Unit[]>([]);
  public units$ = this.unitsSubject.asObservable();

  constructor() {
    this.loadUnits();
  }

async loadUnits(): Promise<void> {
  try {
    const { data: units, error } = await this.supabaseService.getSupabaseClient()
      .from('units')
      .select('*')
      .order('name');

    if (error) throw error;
    
    // Se non esiste più "Confezione", rimuovi questa riga o modifica
    this.unitsSubject.next(units || []);
  } catch (error) {
    console.error('Error loading units:', error);
  }
}


  getUnits(): Unit[] {
    return this.unitsSubject.value;
  }

  getUnitById(id: string): Unit | undefined {
    return this.unitsSubject.value.find(unit => unit.id === id);
  }

  getUnitsByType(type: Unit['type']): Unit[] {
    return this.unitsSubject.value.filter(unit => unit.type === type);
  }

  // CORREZIONE: Gestiamo anche il tipo 'package'
  getBaseUnitForType(type: 'weight' | 'volume' | 'piece' | 'package'): string {
    switch (type) {
      case 'weight': return 'g';
      case 'volume': return 'mL';
      case 'piece': return 'pz';
      case 'package': return 'pz'; // Trattiamo 'package' come 'piece'
      default: return '';
    }
  }

  // Metodo per ottenere unità per tipo di ingrediente
  getUnitsForIngredientType(ingredientType: 'solid' | 'liquid' | 'piece'): Unit[] {
    const unitTypes = {
      'solid': ['weight'],
      'liquid': ['volume'], 
      'piece': ['piece', 'package'] // Includiamo anche 'package'
    };
    
    return this.unitsSubject.value.filter(unit => 
      unitTypes[ingredientType].includes(unit.type)
    );
  }

  // Metodo per ottenere il fattore di conversione
getConversionFactor(unit: Unit): number {
  switch (unit.symbol) {
    case 'kg': return 1000; // 1 kg = 1000 g
    case 'g': return 1;     // 1 g = 1 g
    case 'L': return 1000;  // 1 L = 1000 mL
    case 'mL': return 1;    // 1 mL = 1 mL
    case 'pz': return 1;    // 1 pezzo = 1 pezzo
    default: return 1;
  }
}
}